module mux_2_to_1 (
    input [7:0] in0,
    input [7:0] in1,
    input sel,
    output reg [7:0] out
);
  wire [7:0] _tap_in0 = in0 & {8{1'b1}};


    always @(*) begin
        case (sel)
            1'b0: out = in0;
            1'b1: out = in1;
            default: out = 8'b00000000;
        endcase
    end
endmodule
